use std::{
    env, fs,
    io::Write,
    path::{Path, PathBuf},
};

use anyhow::{Context, Result, bail};
use serde::{Deserialize, Serialize};

use crate::console::read_secret_input;

const DEFAULT_MODEL: &str = "deepseek-v4-pro";
const DEFAULT_SYSTEM_PROMPT: &str = "You are a helpful assistant. when read the file, ignore the build targer files like target dir in rust project, ouptput or dist dir in frontend project.  do not reade the entire project dir tree. read the file in entry file first. do not use the mcp__filesystem__directory_tree in root dir, it maybe cause the context exceed";
const DEFAULT_REASONING_EFFORT: &str = "high";
const DEFAULT_MAX_TOOL_ROUNDS: usize = 100;
const CONFIG_DIR_NAME: &str = ".sparrow_agent";
const CONFIG_FILE_NAME: &str = "config.json";

const DEFAULT_MAX_READ_BYTES: u64 = 262_144;
const DEFAULT_MAX_WRITE_BYTES: u64 = 262_144;

#[derive(Debug, Clone)]
pub struct AppConfig {
    pub api_key: String,
    pub tavily_api_key: String,
    pub model: String,
    pub system_prompt: String,
    pub reasoning_effort: String,
    pub max_tool_rounds: usize,
    pub filesystem: FilesystemConfig,
    pub mcp_servers: Vec<McpServerConfig>,
    pub streaming: StreamingConfig,
}

impl AppConfig {
    pub fn load_or_initialize() -> Result<Self> {
        let config_path = config_path()?;
        let mut stored_config = StoredConfig::load(&config_path)?;
        let mut should_save = false;
        let mut setup_header_printed = false;

        let api_key = match read_env_value("DEEPSEEK_API_KEY").or_else(|| {
            stored_config
                .deepseek_api_key
                .as_deref()
                .and_then(clean_value)
        }) {
            Some(value) => value,
            None => {
                print_setup_header_once(&config_path, &mut setup_header_printed);
                let value = prompt_api_key("DEEPSEEK_API_KEY")?;
                stored_config.deepseek_api_key = Some(value.clone());
                should_save = true;
                value
            }
        };

        let tavily_api_key = match read_env_value("TAVILY_API_KEY").or_else(|| {
            stored_config
                .tavily_api_key
                .as_deref()
                .and_then(clean_value)
        }) {
            Some(value) => value,
            None => {
